@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    // Load initial data during SSR — this renders into the first HTML response.
    protected override void OnInitialized()
    {
        notifications = NotificationService.GetAll();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    // Called only once the component is interactive in the browser (not during SSR).
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            // Simulate a new notification arriving server-side
            NotificationService.SimulateIncoming();

            var newItems = NotificationService.GetSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                _lastSeenId = newItems.Max(n => n.Id);

                await InvokeAsync(() =>
                {
                    notifications.AddRange(newItems);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

